﻿请设计链表结点类Node和链表类LinkList，实现拷贝构造函数和下标运算符重载。要求使用以下main函数，得到类似测试案例的输出。int main()
{
    LinkList L1; 
    LinkList L2(L1); 
    int i;
    for(i=0; i&lt;L2.Count; i++)   L2[i]=L2[i]+1;
    int L1Sum=0;
    for(i=0; i&lt;L1.Count; i++)   L1Sum+=L1[i];
    int L2Sum=0;
    for(i=0; i&lt;L2.Count; i++)   L2Sum+=L2[i];
    cout&lt;&lt;L1Sum&lt;&lt;&quot; &quot;&lt;&lt;L2Sum&lt;&lt;endl;
    return 0;
}
根据输入，构造链表对象L1，拷贝构造链表对象L2。使用下标运算符对L2中的结点进行算术、赋值运算。之后，使用下标运算符对L1和L2中的数据进行求和。最后输出两个和。

﻿查找介于n1与n2（0&lt;n1&lt;n2&lt;32768）之间所有满足下列条件的整数：(1)该数的十进制表示中有且仅有两个相同的数字位；(2)该数是素数。

【含有错误的源程序】
#include&lt;stdio.h&gt;
#include&lt;math.h&gt;
int validate(int n)
{   int i,j,k=0,num[5]={0},size=0;
    do
    {  num[size]=n%10;
          n=n/10;
          size++;
  }while(n&lt;0);
  for(i=0;i&lt;size-1;i++)
        for(j=i+1;j&lt;size;j++)
             if(num[i]==num[j])
                    k=k+1;
       if(k&gt;1)
        return 1;
    else
        return 0;
 }
 int prime(int)
 {   int i;
    for (i=2;i&lt;=(int)sqrt(n);i++)
        if(n%i==0)return 0;
     return 1;
  }
 void main()
 {  int i,count=0,n1,n2;
   scanf(&quot;%d%d&quot;,&amp;n1,&amp;n2);
    for(i=n1;i&lt;=n2;i++)
       {  if(validate(int i)&amp;&amp; prime(int i))
       {   count++;
              printf(&quot;%d\t&quot;,i);
              if(count%8==0)printf(&quot;\n&quot;);
        }
    }
 }

对一个字符串中每个字符（其编码用ch表示）作如下加密操作：(1) 如果ch是小写字母，就用（ch+5）的值的八进制数字字符串替换该字母；
(2)如果ch是大写字母，就用（ch-5）的值的十六进制数字字符串替换该字母；
(3)如果ch是非字母字符则保持愿样。
函数en的功能是将形参c中字符的编码转换成n进制数字字符串并保存到s指向的数组中。函数encrypt的功能是将a指向的字符串按以上要求做加密处理后保存到b指向的数组中。
（题目保证所有字符串长度不超过1000）
【含有错误的源程序】
#include&lt;string.h&gt;
#include&lt;stdio.h&gt;
void en(char c,int n,char s)
{  int t,i=0;
    char temp;
    while(c!=0)
    {   t=c%n;
        if(t&lt;10)
       s[i++]=t+&#39;0&#39;;
        else
       s[i++]=t-10+&#39;A&#39;;
    c=c/10;
    }
    s[i]=&#39;\0&#39;;
    for(t=i-1,i=0;i&lt;t;i++,t--)
       temp=s[i],s[i]=s[t],s[t]=temp;
}
void encrypt(char a[],char b[])
{   char s[4];
    int i;
    for(i=0;a[i]!=&#39;\0&#39;;i++)
    {  if(a[i]&gt;=&#39;a&#39; &amp;&amp; a[i]&lt;=&#39;z&#39;)
           en(a[i]+5,8,s);
       else if(a[i]&gt;=&#39;A&#39; &amp;&amp; a[i]&lt;=&#39;Z&#39;)
                en(a[i]-5,16,s);
            else s[0]=a[i],s[1]=&#39;\0&#39;;
      strcpy(b,s);
     }
}
void main()
{  static char a[30]=&quot;No.1&quot;,b[100];
   encrypt(char a[30],char b[30]);
   puts(b);
}

判断方阵A与B是否相等或方阵A顺时针旋转90度后与方阵B是否相等。设有方阵A和B阶数相同，若方阵A和方阵B对应位置的元素值均相等，则称方阵A等于方阵B；若方阵A经过顺时针旋转90度后形成的新方阵中各元素与方阵B对应位置的元素值均相等，则称方阵A旋转90度后与方阵B相等。
函数equal的功能是，判断a指向的数组中存储的方阵与b指向的数组中存储的方阵是否相等，若相等函数返回1，否则返回0。函数rotate的功能是将a指向的数组中存储的方阵顺时针旋转90度。
【含有错误的源程序】
#include&lt;stdio.h&gt;
#define N 10
int equal(int a[][N],int b[][N],int n)
{  int i,j;
    for(i=0;i&lt;n;i++)
     for(j=0;j&lt;n;j++)
        if (a[i][j]!=b[i][j])
           return 0;
      else return 1;
}
void rotate(int a[][N],int n)
{  int i,j,c[N][N];
   for(i=0;i&lt;n;i++)
      for(j=0;j&lt;n;j++)
      c[i][j]=a[n-j][i];
   for(i=0;i&lt;n;i++)
      for(j=0;j&lt;n;j++)
          a[i][j]=c[i][j];
}
int main()
{  int a[N][N],b[N][N],k, n,i,j;
   scanf(&quot;%d&quot;, &amp;n);
   for(i=0; i&lt;n; i++)
      for(j=0; j&lt;n; j++)  scanf(&quot;%d&quot;, &amp;a[i][j]);
   for(i=0; i&lt;n; i++)
      for(j=0; j&lt;n; j++)  scanf(&quot;%d&quot;, &amp;b[i][j]);
   k=equal(a,b,4);
   i=0;
   if(k) i=1;
   else
   {   rotate(a,b,4);
       k=equal(a,b,4);
       if(k)i=2;
   }
   switch(i);
   { case 0:puts(&quot;A!=B&quot;);  break;
     case 1:puts(&quot;A=B&quot;);    break;
     case 2:puts(&quot;A rotate 90,A=B&quot;);
   }
   return 0;
}

统计一个字符串（长度不超过100）中包含的字母串个数并找出其中最长的字母串。所谓字母串是指一个连续字母序列（不区分大小写），字母串之间用非字母字符分隔。函数count的功能是统计p指向的字符串中包含的字母串个数，并将找出的最长字母串存放在pmax指向的数组中，函数返回字母串的个数。
【含有错误的源程序】
#include&lt;stdio.h&gt;
#include &lt;string.h&gt;
#include &lt;ctype.h&gt;
int count(char p[],char pmax[])
{  int j=0,k,m=0;
   char temp[100];
   while(*p)
   {  while((!isalpha(*p))&amp;&amp;*p) p++;
      k=0;
      if(*p!=&#39;\0&#39;)m++;
      while(isalpha(*p))
        temp[k++]=*p++;
      temp[k]=&quot;\0&quot;;
      if(k&lt;j)    {  j=k;     pmax=temp;    }
    }
    return m;  }
int main()
{  char a[100], max[100];;
   gets(a);
   int i;
   i=count(a[],max[]);
   if(i==0)
     printf(&quot;a=%s:  No letter strings!\n&quot;,a);
   else
     printf(&quot;a=%s\nnumber is%d\nmax string is:%s\n&quot;,a,i,max);
    return 0;
}
